class Solution {
public:
    vector<int> partitionLabels(string s) {
        int last[26];
        for(int i=0;i<(int)s.size();i++) last[s[i]-'a']=i;
        vector<int> ans; int st=0, ed=0;
        for(int i=0;i<(int)s.size();i++){
            ed=max(ed,last[s[i]-'a']);
            if(i==ed){ ans.push_back(ed-st+1); st=i+1; }
        }
        return ans;
    }
};

